import{c as i,Q as t,j as r,m as a}from"./chunks/framework.ByJJFMw8.js";const m=JSON.parse('{"title":"Comparison","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/compare.md","filePath":"en/guide/compare.md","lastUpdated":1782401177000}'),o={name:"en/guide/compare.md"};function n(s,e,l,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h1><p>File Viewer is a pure frontend file preview component for internal tools, intranet systems, and private deployments. It is designed for quick business-file preview, triage, search, print, export, and self-hosted delivery. It is not a professional editor, and it does not promise native-app fidelity for every complex file.</p><h2 id="file-viewer-vs-conversion-services" tabindex="-1">File Viewer vs conversion services <a class="header-anchor" href="#file-viewer-vs-conversion-services" aria-label="Permalink to &quot;File Viewer vs conversion services&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Strengths</th><th>Limits</th></tr></thead><tbody><tr><td>Backend conversion</td><td>Can normalize files to PDF/images for caching, archival workflows, permission auditing, and unified fallback behavior</td><td>Requires conversion workers, queues, temporary files, fonts, caches, retries, and cleanup; private deployment can be costly</td></tr><tr><td>Office Online / cloud services</td><td>High fidelity, low maintenance, mature collaboration features</td><td>Not always suitable for intranet, private deployment, sensitive files, offline environments, or strict compliance requirements</td></tr><tr><td>File Viewer</td><td>Pure frontend, self-hostable, lazy-loaded, and easy to embed in business applications</td><td>Complex Office / CAD files still need real-file regression; not a replacement for professional editors or archival conversion</td></tr></tbody></table><h2 id="when-file-viewer-fits-best" tabindex="-1">When File Viewer fits best <a class="header-anchor" href="#when-file-viewer-fits-best" aria-label="Permalink to &quot;When File Viewer fits best&quot;">​</a></h2><ul><li>Files should not be sent to a third-party conversion service.</li><li>The app runs in an intranet, private deployment, offline environment, or strict CSP setup.</li><li>One component needs to cover Office, PDF/OFD, CAD, archives, email, images, media, code, and structured data.</li><li>The product goal is preview, triage, search, print, export, and download rather than editing.</li><li>The frontend team wants renderer/preset composition instead of many unrelated viewer embeds.</li></ul><h2 id="when-backend-conversion-is-better" tabindex="-1">When backend conversion is better <a class="header-anchor" href="#when-backend-conversion-is-better" aria-label="Permalink to &quot;When backend conversion is better&quot;">​</a></h2><ul><li>Long-term archival requires every file to become a stable PDF or image.</li><li>Very large files make browser memory or mobile performance the main constraint.</li><li>The workflow needs maximum fidelity, batch conversion, OCR, burned-in watermarks, audit records, or asynchronous review queues.</li><li>The team already runs a reliable LibreOffice, OnlyOffice, or commercial conversion service and can absorb the operational cost.</li></ul><h2 id="recommended-mix" tabindex="-1">Recommended mix <a class="header-anchor" href="#recommended-mix" aria-label="Permalink to &quot;Recommended mix&quot;">​</a></h2><p>Many production systems can combine both approaches:</p><ul><li>Use File Viewer for instant browser-side preview by default.</li><li>Trigger backend PDF conversion for archival, contracts, audit, or strict consistency cases.</li><li>Self-host Worker, WASM, font, and vendor assets with the rest of the app&#39;s static resources.</li><li>Collect real compatibility feedback through issues and sanitized samples instead of trusting synthetic files only.</li></ul><h2 id="validation-checklist" tabindex="-1">Validation checklist <a class="header-anchor" href="#validation-checklist" aria-label="Permalink to &quot;Validation checklist&quot;">​</a></h2><ul><li>Try Word, Excel, PowerPoint, PDF, DWG, ZIP, and EML in the <a href="https://demo.file-viewer.app" target="_blank" rel="noreferrer">demo</a>.</li><li>Validate the real formats your product cares about with sanitized files.</li><li>Check mobile WebView behavior, intranet static paths, Worker/WASM MIME types, CSP, and fonts.</li><li>For Office / CAD fidelity, review the <a href="./format-fidelity">format fidelity notes</a>.</li></ul>',13)])])}const p=i(o,[["render",n]]);export{m as __pageData,p as default};
